#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


vec2 huv=uTexSize.zw*0.5;
vec2 aspc=vec2(q2,q1);
vec2 tuv=vUv;
vec3 my_scale,my_mean;
vec3 st,op,sp;
float mscale,i,mavr,j;
vec3 my_smp,c1,c2,c3,c4;
my_scale=texture(sampler_pw_main,vec2(q20,0.004));
mscale=1/(my_scale.z);
//mscale=1/(my_scale.z+1);
my_mean=my_scale.y;

//mscale=1;

vec2 uvr;
vec2 uvof=vec2(q3,q4);


op=texture(main,vUv-uvof*0.002);

sp=texture(base02,0.5+(vUv-0.5)*0.15+uvof.yx*0.15);
sp=sin((sp+texture(base02,0.5+(vUv-0.5)*0.1*(0.8+0.2*my_mean)-uvof*0.1))*M_PI*0.25);
//sp*=0.5;
sp=normalize(sp);
sp=abs(cross(sp,texture(base02,0.5+(vUv-0.5)*0.05*(0.8+0.2*my_mean)-uvof*0.13)));

j=1-lum(op*0.05+sp*0.95);
//j*=j;
i=texture(sampler_pw_main,vec2(q20,j));
i.x*=mscale;
//i=sin(i*M_PI*0.5);
uvr=vUv-0.5;
uvr.x=vUv.x*sin((i*3+q3*0.842)*M_PI_2)+vUv.y*cos((i*3+q3*0.842)*M_PI_2);
uvr.y=vUv.y*sin((i*3+q3*0.842)*M_PI_2)-vUv.x*cos((i*3+q3*0.842)*M_PI_2);

c1=GetPixel(vec2(q3,q4)*0.001+vec2(q4,q3)*0.005*(1-0.1*uvr)*(1-i*i)+0.5+(vUv-0.5)*(i*i*0.2+0.96)*((vRadius.xx*uvr.xy)*0.001+0.999)+(uvr*0.001));

//c2=texture(sampler_pw_main,vec2(q20,lum(c1)));

//c3=GetPixel(0.5+(vUv-0.5)*(c2.z*mscale*0.05+0.95));

//ret=i*i*0.015>my_mean?op*0.1+sp*0.9:c1;
ret=mix(op*0.1+sp*0.9,c1,cos(i*i*M_PI*0.5));

ret*=((1-i*i)*0.005+0.997);

//ret=tex2d(base01,0.5+(vUv-0.5)*(i*0.1+0.9));
//ret=i<my_mean?ret*ret:ret;
//ret=mix(ret,op,1-i);
//ret=mix(ret,GetPixel(0.5+(vUv-0.5)*(i*0.05+0.95)),i);
//ret=i>0?my_mean/*tex2d(base01,vUv.xy)*/:0;
//ret=my_smp.z;
//ret*=(0.01*(1-i*i)+0.99);
//ret.=fract(ret+1.431*sin((ret+q3*0.3)*M_PI_2*0.531));
//ret=i>my_mean?i:0;



  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


vec2 uv1 = vUv-.5;

vec3 ret1 = texture(sampler_main, vUv) +0.03*(1-vRadius);


vec2 hor = vec2 (uTexSize.z,0);
vec2 ver = vec2 (0,uTexSize.w);
float dx = GetPixel (vUv-hor) - GetPixel (vUv+hor);
float dy = GetPixel (vUv-ver) - GetPixel (vUv+ver);
vec2 dz = vec2 (dx,dy);

uv1 = uv1*0+.3*cos(uv1*2) - dz;;
float dots = clamp01(.04/length(uv1));
uv1 = uv1*0+.3*cos(uv1*12) - 9*dz;;
vec3 dots2 = clamp01(.04/length(uv1));
ret = dots + GetPixel(vUv)*12*dots2;

//ret.xyz=sin((ret.xyz+lum(ret1))*M_PI*0.5);
//ret.xyz=sin(cos(ret.xyz*3+ret1.xyz*5.5+_qc.zyx*26*(lum(ret1).xxx*0.1+0.9).xyz)*M_PI*0.5);
//ret.y=sin(cos(ret.y*3+ret1.y*5.5+_qc.y*26*(lum(ret1)*0.1+0.9))*M_PI*0.5);
//ret.z=sin(sin(ret.z*3+ret1.z*5.5+_qc.x*26*(lum(ret1)*0.1+0.9))*M_PI*0.5);
ret*=ret;

  fragColor = ret;
}
